import React from 'react';
import './Projects.css';

const PROJECTS = [
  {
    id: 1,
    title: 'Mark Cuban - Billionaire Journey',
    category: 'YouTube',
    year: '2024',
    desc: 'Long-form documentary edit, 2.1M views',
    accent: '--blue',
  },
  {
    id: 2,
    title: 'Brand Anthem - Nike India',
    category: 'Commercial',
    year: '2024',
    desc: '60s brand spot, color graded in DaVinci',
    accent: '--pink',
  },
  {
    id: 3,
    title: 'Afterglow - Music Video',
    category: 'Music Video',
    year: '2023',
    desc: 'Cinematic MV, 540K views on YouTube',
    accent: '--lavender',
  },
  {
    id: 4,
    title: 'Delwinder - Sports Doc',
    category: 'Documentary',
    year: '2024',
    desc: '10-min sports documentary, film festivals',
    accent: '--blue',
  },
  {
    id: 5,
    title: 'Post Breakup Emotions',
    category: 'Short Film',
    year: '2023',
    desc: 'Narrative short, festival circuit',
    accent: '--pink',
  },
  {
    id: 6,
    title: 'Finance Creator Package',
    category: 'YouTube',
    year: '2024',
    desc: 'Ongoing editing for 920K subscriber channel',
    accent: '--lavender',
  },
];

export default function Projects() {
  return (
    <section id="projects" className="section projects-section reveal" data-delay="0">
      <div className="section-inner">
        <h2 className="section-heading">Selected Work</h2>
        <p className="section-sub">A few things I&apos;ve crafted recently.</p>

        <div className="project-grid">
          {PROJECTS.map((project) => (
            <article className="project-card" key={project.id}>
              <span className="project-accent" style={{ '--accent': `var(${project.accent})` }} />
              <span className="project-badge" style={{ '--accent': `var(${project.accent})` }}>
                {project.category}
              </span>
              <h3>{project.title}</h3>
              <p>{project.desc}</p>
              <div className="project-foot">
                <span>{project.year}</span>
                <span>?</span>
              </div>
            </article>
          ))}
        </div>
      </div>
    </section>
  );
}
